/**
 * MMS Application Styles
 *
 * Layout styles for the main application shell.
 * Based on specs/006-user-interface.md Section 6.2.
 */

/* Root Application Container */
.mms-app {
  display: flex;
  flex-direction: column;
  height: 100vh;
  width: 100vw;
  overflow: hidden;
  background-color: var(--pt-app-background-color, #f5f8fa);
}

/* Dark theme support */
.mms-app.bp5-dark {
  background-color: #1c2127;
}

/* Main Container (below fixed header) */
.mms-main {
  display: flex;
  flex-direction: column;
  flex: 1;
  margin-top: 50px; /* Height of Navbar */
  overflow: hidden;
}

/* Content Area (sidebar + canvas) */
.mms-content {
  display: flex;
  flex: 1;
  overflow: hidden;
}

/* Header Styles */
.mms-header {
  z-index: 20;
}

.mms-logo {
  font-size: 16px;
  color: var(--pt-text-color, #182026);
}

.mms-app.bp5-dark .mms-logo {
  color: #f5f8fa;
}

/* Toolbar Styles */
.mms-toolbar {
  flex-shrink: 0;
  z-index: 10;
}

/* Sidebar Styles */
.mms-sidebar {
  flex-shrink: 0;
  z-index: 5;
}

/* Canvas Styles */
.mms-canvas {
  flex: 1;
  position: relative;
}

/* Status Bar Styles */
.mms-status-bar {
  flex-shrink: 0;
  z-index: 10;
}

/* Scrollbar Styling */
.mms-sidebar::-webkit-scrollbar {
  width: 6px;
}

.mms-sidebar::-webkit-scrollbar-track {
  background: transparent;
}

.mms-sidebar::-webkit-scrollbar-thumb {
  background-color: rgba(0, 0, 0, 0.2);
  border-radius: 3px;
}

.mms-sidebar::-webkit-scrollbar-thumb:hover {
  background-color: rgba(0, 0, 0, 0.3);
}

/* Dark theme scrollbar */
.mms-app.bp5-dark .mms-sidebar::-webkit-scrollbar-thumb {
  background-color: rgba(255, 255, 255, 0.2);
}

.mms-app.bp5-dark .mms-sidebar::-webkit-scrollbar-thumb:hover {
  background-color: rgba(255, 255, 255, 0.3);
}

/* Canvas placeholder states */
.mms-canvas .bp5-non-ideal-state {
  max-width: 400px;
  margin: 0 auto;
}

/* Loading and transition states */
.mms-loading {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  width: 100%;
}

/* Overlay panels (man-hour, drift) - will be positioned absolute */
.mms-overlay-panel {
  position: absolute;
  right: 16px;
  bottom: 60px;
  width: 280px;
  max-height: 300px;
  overflow-y: auto;
  z-index: 15;
}

/* Minimap - positioned in bottom right corner */
.mms-minimap {
  position: absolute;
  right: 16px;
  top: 60px;
  width: 200px;
  height: 120px;
  border: 1px solid var(--pt-divider-black, #e1e8ed);
  border-radius: 4px;
  background-color: white;
  z-index: 15;
}

.mms-app.bp5-dark .mms-minimap {
  background-color: #2f343c;
  border-color: #404854;
}

/* Keyboard shortcut hint */
.mms-shortcut-hint {
  position: fixed;
  bottom: 50px;
  right: 16px;
  padding: 8px 12px;
  background-color: rgba(0, 0, 0, 0.8);
  color: white;
  border-radius: 4px;
  font-size: 12px;
  z-index: 100;
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.2s;
}

.mms-shortcut-hint.visible {
  opacity: 1;
}

/* Drag preview layer */
.mms-drag-preview {
  position: fixed;
  pointer-events: none;
  z-index: 1000;
}

/* Toast container override for MMS positioning */
.mms-app .bp5-toast-container {
  top: 60px !important;
}

/* Animation utilities */
@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

.mms-syncing {
  animation: pulse 1.5s ease-in-out infinite;
}

/* Responsive adjustments */
@media (max-width: 1200px) {
  .mms-sidebar {
    width: 220px !important;
  }
}

@media (max-width: 900px) {
  .mms-sidebar {
    width: 200px !important;
  }

  .mms-toolbar {
    flex-wrap: wrap;
    padding: 4px 8px !important;
  }
}

