     1→/**
     2→ * Accessibility Announcer Utility
     3→ *
     4→ * Provides screen reader announcements for canvas state changes.
     5→ * Uses ARIA live regions to announce changes to assistive technology users.
     6→ *
     7→ * @see WCAG 2.1 Success Criterion 4.1.3 Status Messages
     8→ * @see specs/006-user-interface.md Section 6.10 (Accessibility)
     9→ */
    10→
    11→// =============================================================================
    12→// Types
    13→// =============================================================================
    14→
    15→/**
    16→ * Priority level for announcements:
    17→ * - polite: Wait for current announcements to finish (default)
    18→ * - assertive: Interrupt current announcements immediately
    19→ */
    20→export type AnnouncementPriority = 'polite' | 'assertive';
    21→
    22→/**
    23→ * Announcement categories for better organization and filtering
    24→ */
    25→export type AnnouncementCategory =
    26→  | 'navigation' // Zoom, pan, view changes
    27→  | 'selection' // PM or train selection changes
    28→  | 'drag' // Drag-and-drop operations
    29→  | 'data' // Data loading states
    30→  | 'validation' // Constraint validation results
    31→  | 'action'; // User action feedback
    32→
    33→/**
    34→ * Announcement message configuration
    35→ */
    36→export interface Announcement {
    37→  message: string;
    38→  priority: AnnouncementPriority;
    39→  category: AnnouncementCategory;
    40→  timestamp: number;
    41→}
    42→
    43→// =============================================================================
    44→// Announcer Singleton
    45→// =============================================================================
    46→
    47→let politeRegion: HTMLElement | null = null;
    48→let assertiveRegion: HTMLElement | null = null;
    49→let announcementHistory: Announcement[] = [];
    50→const MAX_HISTORY = 50;
    51→
    52→/**
    53→ * Creates the ARIA live regions if they don't exist.
    54→ * Should be called once when the application starts.
    55→ */
    56→export function initializeAnnouncer(): void {
    57→  if (typeof document === 'undefined') return;
    58→
    59→  // Create polite live region
    60→  if (!politeRegion) {
    61→    politeRegion = document.createElement('div');
    62→    politeRegion.setAttribute('id', 'mms-a11y-polite');
    63→    politeRegion.setAttribute('role', 'status');
    64→    politeRegion.setAttribute('aria-live', 'polite');
    65→    politeRegion.setAttribute('aria-atomic', 'true');
    66→    applyHiddenStyles(politeRegion);
    67→    document.body.appendChild(politeRegion);
    68→  }
    69→
    70→  // Create assertive live region
    71→  if (!assertiveRegion) {
    72→    assertiveRegion = document.createElement('div');
    73→    assertiveRegion.setAttribute('id', 'mms-a11y-assertive');
    74→    assertiveRegion.setAttribute('role', 'alert');
    75→    assertiveRegion.setAttribute('aria-live', 'assertive');
    76→    assertiveRegion.setAttribute('aria-atomic', 'true');
    77→    applyHiddenStyles(assertiveRegion);
    78→    document.body.appendChild(assertiveRegion);
    79→  }
    80→}
    81→
    82→/**
    83→ * Cleans up the ARIA live regions.
    84→ * Should be called when the application unmounts.
    85→ */
    86→export function destroyAnnouncer(): void {
    87→  if (politeRegion?.parentNode) {
    88→    politeRegion.parentNode.removeChild(politeRegion);
    89→    politeRegion = null;
    90→  }
    91→  if (assertiveRegion?.parentNode) {
    92→    assertiveRegion.parentNode.removeChild(assertiveRegion);
    93→    assertiveRegion = null;
    94→  }
    95→  announcementHistory = [];
    96→}
    97→
    98→/**
    99→ * Applies visually hidden styles to an element while keeping it accessible
   100→ * to screen readers. Uses the standard "sr-only" technique.
   101→ */
   102→function applyHiddenStyles(element: HTMLElement): void {
   103→  element.style.cssText = `
   104→    position: absolute;
   105→    width: 1px;
   106→    height: 1px;
   107→    padding: 0;
   108→    margin: -1px;
   109→    overflow: hidden;
   110→    clip: rect(0, 0, 0, 0);
   111→    white-space: nowrap;
   112→    border: 0;
   113→  `;
   114→}
   115→
   116→// =============================================================================
   117→// Core Announcement Functions
   118→// =============================================================================
   119→
   120→/**
   121→ * Announces a message to screen reader users.
   122→ *
   123→ * @param message - The message to announce
   124→ * @param options - Configuration options
   125→ * @returns The announcement object
   126→ */
   127→export function announce(
   128→  message: string,
   129→  options: {
   130→    priority?: AnnouncementPriority;
   131→    category?: AnnouncementCategory;
   132→  } = {}
   133→): Announcement {
   134→  const priority = options.priority ?? 'polite';
   135→  const category = options.category ?? 'action';
   136→
   137→  const announcement: Announcement = {
   138→    message,
   139→    priority,
   140→    category,
   141→    timestamp: Date.now(),
   142→  };
   143→
   144→  // Add to history
   145→  announcementHistory.push(announcement);
   146→  if (announcementHistory.length > MAX_HISTORY) {
   147→    announcementHistory.shift();
   148→  }
   149→
   150→  // Initialize if needed
   151→  if (!politeRegion || !assertiveRegion) {
   152→    initializeAnnouncer();
   153→  }
   154→
   155→  // Set the message in the appropriate live region
   156→  const region = priority === 'assertive' ? assertiveRegion : politeRegion;
   157→  if (region) {
   158→    // Clear and set message (forces re-announcement)
   159→    region.textContent = '';
   160→    // Use setTimeout to ensure the clear takes effect
   161→    setTimeout(() => {
   162→      region.textContent = message;
   163→    }, 50);
   164→  }
   165→
   166→  return announcement;
   167→}
   168→
   169→/**
   170→ * Gets the announcement history (for debugging/testing)
   171→ */
   172→export function getAnnouncementHistory(): readonly Announcement[] {
   173→  return announcementHistory;
   174→}
   175→
   176→/**
   177→ * Clears the announcement history
   178→ */
   179→export function clearAnnouncementHistory(): void {
   180→  announcementHistory = [];
   181→}
   182→
   183→// =============================================================================
   184→// Convenience Functions for Common Announcements
   185→// =============================================================================
   186→
   187→/**
   188→ * Announces a zoom level change
   189→ */
   190→export function announceZoomChange(
   191→  zoomLevel: string,
   192→  zoomPercent?: number
   193→): Announcement {
   194→  const message = zoomPercent
   195→    ? `Zoom level: ${zoomLevel}, ${Math.round(zoomPercent)}%`
   196→    : `Zoom level: ${zoomLevel}`;
   197→  return announce(message, { category: 'navigation', priority: 'polite' });
   198→}
   199→
   200→/**
   201→ * Announces a navigation to a specific date
   202→ */
   203→export function announceNavigateToDate(date: string): Announcement {
   204→  return announce(`Navigated to ${date}`, {
   205→    category: 'navigation',
   206→    priority: 'polite',
   207→  });
   208→}
   209→
   210→/**
   211→ * Announces PM selection
   212→ */
   213→export function announcePmSelection(
   214→  pmCode: string,
   215→  trainNumber: string,
   216→  date: string
   217→): Announcement {
   218→  return announce(
   219→    `Selected PM ${pmCode} for train ${trainNumber} on ${date}`,
   220→    { category: 'selection', priority: 'polite' }
   221→  );
   222→}
   223→
   224→/**
   225→ * Announces PM deselection
   226→ */
   227→export function announcePmDeselection(): Announcement {
   228→  return announce('Selection cleared', {
   229→    category: 'selection',
   230→    priority: 'polite',
   231→  });
   232→}
   233→
   234→/**
   235→ * Announces train selection
   236→ */
   237→export function announceTrainSelection(
   238→  trainNumber: string,
   239→  fleetCode?: string
   240→): Announcement {
   241→  const message = fleetCode
   242→    ? `Selected train ${trainNumber} from fleet ${fleetCode}`
   243→    : `Selected train ${trainNumber}`;
   244→  return announce(message, { category: 'selection', priority: 'polite' });
   245→}
   246→
   247→/**
   248→ * Announces the start of a drag operation
   249→ */
   250→export function announceDragStart(
   251→  pmCode: string,
   252→  trainNumber: string,
   253→  sourceDate: string
   254→): Announcement {
   255→  return announce(
