     1→/**
     2→ * Focus Management Utility
     3→ *
     4→ * Provides keyboard-accessible focus navigation within the canvas.
     5→ * Manages focus between PM blocks and other focusable elements.
     6→ *
     7→ * @see WCAG 2.1 Success Criterion 2.1.1 Keyboard
     8→ * @see WCAG 2.1 Success Criterion 2.4.3 Focus Order
     9→ * @see WCAG 2.1 Success Criterion 2.4.7 Focus Visible
    10→ */
    11→
    12→// =============================================================================
    13→// Types
    14→// =============================================================================
    15→
    16→/**
    17→ * Represents a focusable item in the canvas
    18→ */
    19→export interface FocusableItem {
    20→  id: string;
    21→  type: 'pm' | 'train' | 'cell' | 'control';
    22→  row: number; // Vertical position (train index)
    23→  col: number; // Horizontal position (date/time index)
    24→  label: string;
    25→  isDisabled?: boolean;
    26→}
    27→
    28→/**
    29→ * Focus navigation direction
    30→ */
    31→export type FocusDirection = 'up' | 'down' | 'left' | 'right' | 'first' | 'last';
    32→
    33→/**
    34→ * Focus state for the canvas
    35→ */
    36→export interface FocusState {
    37→  focusedItemId: string | null;
    38→  focusedItemType: FocusableItem['type'] | null;
    39→  focusedRow: number;
    40→  focusedCol: number;
    41→  isFocusVisible: boolean;
    42→}
    43→
    44→// =============================================================================
    45→// Focus Ring Styles
    46→// =============================================================================
    47→
    48→/**
    49→ * CSS styles for the visible focus ring.
    50→ * Meets WCAG 2.1 AA contrast requirements.
    51→ */
    52→export const FOCUS_RING_STYLES = {
    53→  default: {
    54→    outline: '2px solid #2563eb', // Blue-600, high contrast
    55→    outlineOffset: '2px',
    56→    boxShadow: '0 0 0 4px rgba(37, 99, 235, 0.25)',
    57→  },
    58→  error: {
    59→    outline: '2px solid #dc2626', // Red-600, for invalid states
    60→    outlineOffset: '2px',
    61→    boxShadow: '0 0 0 4px rgba(220, 38, 38, 0.25)',
    62→  },
    63→  success: {
    64→    outline: '2px solid #16a34a', // Green-600, for valid states
    65→    outlineOffset: '2px',
    66→    boxShadow: '0 0 0 4px rgba(22, 163, 74, 0.25)',
    67→  },
    68→};
    69→
    70→/**
    71→ * Returns CSS style object for focus ring
    72→ */
    73→export function getFocusRingStyle(
    74→  variant: 'default' | 'error' | 'success' = 'default'
    75→): React.CSSProperties {
    76→  return FOCUS_RING_STYLES[variant] as unknown as React.CSSProperties;
    77→}
    78→
    79→// =============================================================================
    80→// Focus Grid Management
    81→// =============================================================================
    82→
    83→/**
    84→ * Creates a 2D grid of focusable items for arrow key navigation.
    85→ * Items are sorted by row (train) then column (date).
    86→ */
    87→export function createFocusGrid(items: FocusableItem[]): FocusableItem[][] {
    88→  if (items.length === 0) return [];
    89→
    90→  // Find the max row and column
    91→  const maxRow = Math.max(...items.map((i) => i.row));
    92→  const maxCol = Math.max(...items.map((i) => i.col));
    93→
    94→  // Create the grid
    95→  const grid: FocusableItem[][] = [];
    96→  for (let r = 0; r <= maxRow; r++) {
    97→    const row: FocusableItem[] = [];
    98→    for (let c = 0; c <= maxCol; c++) {
    99→      const item = items.find((i) => i.row === r && i.col === c && !i.isDisabled);
   100→      if (item) {
   101→        row.push(item);
   102→      }
   103→    }
   104→    if (row.length > 0) {
   105→      grid.push(row);
   106→    }
   107→  }
   108→
   109→  return grid;
   110→}
   111→
   112→/**
   113→ * Finds the next focusable item in the given direction.
   114→ */
   115→export function findNextFocusableItem(
   116→  items: FocusableItem[],
   117→  currentItem: FocusableItem | null,
   118→  direction: FocusDirection
   119→): FocusableItem | null {
   120→  const enabledItems = items.filter((i) => !i.isDisabled);
   121→  if (enabledItems.length === 0) return null;
   122→
   123→  // Handle first/last
   124→  if (direction === 'first') {
   125→    return enabledItems.sort((a, b) => a.row - b.row || a.col - b.col)[0] ?? null;
   126→  }
   127→  if (direction === 'last') {
   128→    return enabledItems.sort((a, b) => b.row - a.row || b.col - a.col)[0] ?? null;
   129→  }
   130→
   131→  // If no current item, return first
   132→  if (!currentItem) {
   133→    return findNextFocusableItem(items, null, 'first');
   134→  }
   135→
   136→  // Build grid for navigation
   137→  const grid = createFocusGrid(enabledItems);
   138→  if (grid.length === 0) return null;
   139→
   140→  // Find current position in grid
   141→  let currentRowIdx = -1;
   142→  let currentColIdx = -1;
   143→  for (let r = 0; r < grid.length; r++) {
   144→    const colIdx = grid[r].findIndex((i) => i.id === currentItem.id);
   145→    if (colIdx !== -1) {
   146→      currentRowIdx = r;
   147→      currentColIdx = colIdx;
   148→      break;
   149→    }
   150→  }
   151→
   152→  // If current item not found, return first
   153→  if (currentRowIdx === -1) {
   154→    return findNextFocusableItem(items, null, 'first');
   155→  }
   156→
   157→  // Navigate based on direction
   158→  switch (direction) {
   159→    case 'up': {
   160→      if (currentRowIdx > 0) {
   161→        const targetRow = grid[currentRowIdx - 1];
   162→        // Find closest column in the row above
   163→        const targetColIdx = Math.min(currentColIdx, targetRow.length - 1);
   164→        return targetRow[targetColIdx] ?? null;
   165→      }
   166→      // Wrap to bottom
   167→      const bottomRow = grid[grid.length - 1];
   168→      const targetColIdx = Math.min(currentColIdx, bottomRow.length - 1);
   169→      return bottomRow[targetColIdx] ?? null;
   170→    }
   171→    case 'down': {
   172→      if (currentRowIdx < grid.length - 1) {
   173→        const targetRow = grid[currentRowIdx + 1];
   174→        const targetColIdx = Math.min(currentColIdx, targetRow.length - 1);
   175→        return targetRow[targetColIdx] ?? null;
   176→      }
   177→      // Wrap to top
   178→      const topRow = grid[0];
   179→      const targetColIdx = Math.min(currentColIdx, topRow.length - 1);
   180→      return topRow[targetColIdx] ?? null;
   181→    }
   182→    case 'left': {
   183→      const currentRow = grid[currentRowIdx];
   184→      if (currentColIdx > 0) {
   185→        return currentRow[currentColIdx - 1] ?? null;
   186→      }
   187→      // Wrap to end of row
   188→      return currentRow[currentRow.length - 1] ?? null;
   189→    }
   190→    case 'right': {
   191→      const currentRow = grid[currentRowIdx];
   192→      if (currentColIdx < currentRow.length - 1) {
   193→        return currentRow[currentColIdx + 1] ?? null;
   194→      }
   195→      // Wrap to start of row
   196→      return currentRow[0] ?? null;
   197→    }
   198→    default:
   199→      return null;
   200→  }
   201→}
   202→
   203→// =============================================================================
   204→// Focus Trap for Dialogs
   205→// =============================================================================
   206→
   207→/**
   208→ * Gets all focusable elements within a container.
   209→ */
   210→export function getFocusableElements(container: HTMLElement): HTMLElement[] {
   211→  const selector = [
   212→    'a[href]',
   213→    'button:not([disabled])',
   214→    'input:not([disabled])',
   215→    'select:not([disabled])',
   216→    'textarea:not([disabled])',
   217→    '[tabindex]:not([tabindex="-1"])',
   218→  ].join(', ');
   219→
   220→  return Array.from(container.querySelectorAll<HTMLElement>(selector)).filter(
   221→    (el) => !el.hasAttribute('disabled') && el.offsetParent !== null
   222→  );
   223→}
   224→
