/**
 * Focus Management Utility
 *
 * Provides keyboard-accessible focus navigation within the canvas.
 * Manages focus between PM blocks and other focusable elements.
 *
 * @see WCAG 2.1 Success Criterion 2.1.1 Keyboard
 * @see WCAG 2.1 Success Criterion 2.4.3 Focus Order
 * @see WCAG 2.1 Success Criterion 2.4.7 Focus Visible
 */

// =============================================================================
// Types
// =============================================================================

/**
 * Represents a focusable item in the canvas
 */
export interface FocusableItem {
  id: string;
  type: 'pm' | 'train' | 'cell' | 'control';
  row: number; // Vertical position (train index)
  col: number; // Horizontal position (date/time index)
  label: string;
  isDisabled?: boolean;
}

/**
 * Focus navigation direction
 */
export type FocusDirection = 'up' | 'down' | 'left' | 'right' | 'first' | 'last';

/**
 * Focus state for the canvas
 */
export interface FocusState {
  focusedItemId: string | null;
  focusedItemType: FocusableItem['type'] | null;
  focusedRow: number;
  focusedCol: number;
  isFocusVisible: boolean;
}

// =============================================================================
// Focus Ring Styles
// =============================================================================

/**
 * CSS styles for the visible focus ring.
 * Meets WCAG 2.1 AA contrast requirements.
 */
export const FOCUS_RING_STYLES = {
  default: {
    outline: '2px solid #2563eb', // Blue-600, high contrast
    outlineOffset: '2px',
    boxShadow: '0 0 0 4px rgba(37, 99, 235, 0.25)',
  },
  error: {
    outline: '2px solid #dc2626', // Red-600, for invalid states
    outlineOffset: '2px',
    boxShadow: '0 0 0 4px rgba(220, 38, 38, 0.25)',
  },
  success: {
    outline: '2px solid #16a34a', // Green-600, for valid states
    outlineOffset: '2px',
    boxShadow: '0 0 0 4px rgba(22, 163, 74, 0.25)',
  },
};

/**
 * Returns CSS style object for focus ring
 */
export function getFocusRingStyle(
  variant: 'default' | 'error' | 'success' = 'default'
): React.CSSProperties {
  return FOCUS_RING_STYLES[variant] as unknown as React.CSSProperties;
}

// =============================================================================
// Focus Grid Management
// =============================================================================

/**
 * Creates a 2D grid of focusable items for arrow key navigation.
 * Items are sorted by row (train) then column (date).
 */
export function createFocusGrid(items: FocusableItem[]): FocusableItem[][] {
  if (items.length === 0) return [];

  // Find the max row and column
  const maxRow = Math.max(...items.map((i) => i.row));
  const maxCol = Math.max(...items.map((i) => i.col));

  // Create the grid
  const grid: FocusableItem[][] = [];
  for (let r = 0; r <= maxRow; r++) {
    const row: FocusableItem[] = [];
    for (let c = 0; c <= maxCol; c++) {
      const item = items.find((i) => i.row === r && i.col === c && !i.isDisabled);
      if (item) {
        row.push(item);
      }
    }
    if (row.length > 0) {
      grid.push(row);
    }
  }

  return grid;
}

/**
 * Finds the next focusable item in the given direction.
 */
export function findNextFocusableItem(
  items: FocusableItem[],
  currentItem: FocusableItem | null,
  direction: FocusDirection
): FocusableItem | null {
  const enabledItems = items.filter((i) => !i.isDisabled);
  if (enabledItems.length === 0) return null;

  // Handle first/last
  if (direction === 'first') {
    return enabledItems.sort((a, b) => a.row - b.row || a.col - b.col)[0] ?? null;
  }
  if (direction === 'last') {
    return enabledItems.sort((a, b) => b.row - a.row || b.col - a.col)[0] ?? null;
  }

  // If no current item, return first
  if (!currentItem) {
    return findNextFocusableItem(items, null, 'first');
  }

  // Build grid for navigation
  const grid = createFocusGrid(enabledItems);
  if (grid.length === 0) return null;

  // Find current position in grid
  let currentRowIdx = -1;
  let currentColIdx = -1;
  for (let r = 0; r < grid.length; r++) {
    const colIdx = grid[r].findIndex((i) => i.id === currentItem.id);
    if (colIdx !== -1) {
      currentRowIdx = r;
      currentColIdx = colIdx;
      break;
    }
  }

  // If current item not found, return first
  if (currentRowIdx === -1) {
    return findNextFocusableItem(items, null, 'first');
  }

  // Navigate based on direction
  switch (direction) {
    case 'up': {
      if (currentRowIdx > 0) {
        const targetRow = grid[currentRowIdx - 1];
        // Find closest column in the row above
        const targetColIdx = Math.min(currentColIdx, targetRow.length - 1);
        return targetRow[targetColIdx] ?? null;
      }
      // Wrap to bottom
      const bottomRow = grid[grid.length - 1];
      const targetColIdx = Math.min(currentColIdx, bottomRow.length - 1);
      return bottomRow[targetColIdx] ?? null;
    }
    case 'down': {
      if (currentRowIdx < grid.length - 1) {
        const targetRow = grid[currentRowIdx + 1];
        const targetColIdx = Math.min(currentColIdx, targetRow.length - 1);
        return targetRow[targetColIdx] ?? null;
      }
      // Wrap to top
      const topRow = grid[0];
      const targetColIdx = Math.min(currentColIdx, topRow.length - 1);
      return topRow[targetColIdx] ?? null;
    }
    case 'left': {
      const currentRow = grid[currentRowIdx];
      if (currentColIdx > 0) {
        return currentRow[currentColIdx - 1] ?? null;
      }
      // Wrap to end of row
      return currentRow[currentRow.length - 1] ?? null;
    }
    case 'right': {
      const currentRow = grid[currentRowIdx];
      if (currentColIdx < currentRow.length - 1) {
        return currentRow[currentColIdx + 1] ?? null;
      }
      // Wrap to start of row
      return currentRow[0] ?? null;
    }
    default:
      return null;
  }
}

// =============================================================================
// Focus Trap for Dialogs
// =============================================================================

/**
 * Gets all focusable elements within a container.
 */
export function getFocusableElements(container: HTMLElement): HTMLElement[] {
  const selector = [
    'a[href]',
    'button:not([disabled])',
    'input:not([disabled])',
    'select:not([disabled])',
    'textarea:not([disabled])',
    '[tabindex]:not([tabindex="-1"])',
  ].join(', ');

  return Array.from(container.querySelectorAll<HTMLElement>(selector)).filter(
    (el) => !el.hasAttribute('disabled') && el.offsetParent !== null
  );
}

/**
 * Creates a focus trap within a container.
 * Returns a cleanup function.
 */
export function createFocusTrap(container: HTMLElement): () => void {
  const handleKeyDown = (event: KeyboardEvent) => {
    if (event.key !== 'Tab') return;

    const focusables = getFocusableElements(container);
    if (focusables.length === 0) return;

    const first = focusables[0];
    const last = focusables[focusables.length - 1];
    const active = document.activeElement as HTMLElement;

    if (event.shiftKey) {
      // Shift+Tab
      if (active === first) {
        event.preventDefault();
        last.focus();
      }
    } else {
      // Tab
      if (active === last) {
        event.preventDefault();
        first.focus();
      }
    }
  };

  container.addEventListener('keydown', handleKeyDown);

  // Focus the first focusable element
  const focusables = getFocusableElements(container);
  if (focusables.length > 0) {
    focusables[0].focus();
  }

  return () => {
    container.removeEventListener('keydown', handleKeyDown);
  };
}

// =============================================================================
// Reduced Motion Detection
// =============================================================================

/**
 * Checks if the user prefers reduced motion.
 * Uses the prefers-reduced-motion media query.
 */
export function prefersReducedMotion(): boolean {
  if (typeof window === 'undefined') return false;
  return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

/**
 * Creates a listener for prefers-reduced-motion changes.
 * Returns a cleanup function.
 */
export function onReducedMotionChange(
  callback: (prefersReducedMotion: boolean) => void
): () => void {
  if (typeof window === 'undefined') return () => {};

  const mq = window.matchMedia('(prefers-reduced-motion: reduce)');

  const handler = (event: MediaQueryListEvent) => {
    callback(event.matches);
  };

  mq.addEventListener('change', handler);
  return () => mq.removeEventListener('change', handler);
}

// =============================================================================
// High Contrast Mode Detection
// =============================================================================

/**
 * Checks if the user prefers high contrast mode.
 * Uses the prefers-contrast media query.
 */
export function prefersHighContrast(): boolean {
  if (typeof window === 'undefined') return false;
  return (
    window.matchMedia('(prefers-contrast: more)').matches ||
    window.matchMedia('(-ms-high-contrast: active)').matches
  );
}

/**
 * Creates a listener for high contrast mode changes.
 */
export function onHighContrastChange(
  callback: (prefersHighContrast: boolean) => void
): () => void {
  if (typeof window === 'undefined') return () => {};

  const mq = window.matchMedia('(prefers-contrast: more)');

  const handler = (event: MediaQueryListEvent) => {
    callback(event.matches);
  };

  mq.addEventListener('change', handler);
  return () => mq.removeEventListener('change', handler);
}

// =============================================================================
// Skip Link Support
// =============================================================================

/**
 * Creates a skip link for keyboard users to bypass navigation.
 */
export function createSkipLink(
  targetId: string,
  label: string = 'Skip to main content'
): HTMLAnchorElement {
  const link = document.createElement('a');
  link.href = `#${targetId}`;
  link.className = 'mms-skip-link';
  link.textContent = label;

  // Visually hidden until focused
  link.style.cssText = `
    position: absolute;
    left: -10000px;
    top: auto;
    width: 1px;
    height: 1px;
    overflow: hidden;
  `;

  // Show on focus
  link.addEventListener('focus', () => {
    link.style.cssText = `
      position: absolute;
      left: 0;
      top: 0;
      z-index: 10000;
      padding: 8px 16px;
      background: #2563eb;
      color: white;
      text-decoration: none;
      font-weight: bold;
      border-radius: 0 0 4px 0;
    `;
  });

  link.addEventListener('blur', () => {
    link.style.cssText = `
      position: absolute;
      left: -10000px;
      top: auto;
      width: 1px;
      height: 1px;
      overflow: hidden;
    `;
  });

  return link;
}

// =============================================================================
// Roving Tabindex Pattern
// =============================================================================

/**
 * Implements the roving tabindex pattern for a list of items.
 * Only the focused item has tabindex="0", others have tabindex="-1".
 */
export function updateRovingTabindex(
  items: HTMLElement[],
  focusedIndex: number
): void {
  items.forEach((item, index) => {
    if (index === focusedIndex) {
      item.setAttribute('tabindex', '0');
    } else {
      item.setAttribute('tabindex', '-1');
    }
  });
}

/**
 * Handles keyboard navigation for roving tabindex.
 * Returns the new focused index.
 */
export function handleRovingTabindexKeydown(
  event: KeyboardEvent,
  currentIndex: number,
  itemCount: number,
  orientation: 'horizontal' | 'vertical' = 'vertical'
): number | null {
  const isHorizontal = orientation === 'horizontal';
  const prevKey = isHorizontal ? 'ArrowLeft' : 'ArrowUp';
  const nextKey = isHorizontal ? 'ArrowRight' : 'ArrowDown';

  switch (event.key) {
    case prevKey:
      event.preventDefault();
      return currentIndex > 0 ? currentIndex - 1 : itemCount - 1;
    case nextKey:
      event.preventDefault();
      return currentIndex < itemCount - 1 ? currentIndex + 1 : 0;
    case 'Home':
      event.preventDefault();
      return 0;
    case 'End':
      event.preventDefault();
      return itemCount - 1;
    default:
      return null;
  }
}

